import { QueryClient } from '@tanstack/react-query';

export const TIMEFRAME_PRESETS_QUERY_KEY = ['getTimeframePresets'] as const;

/**
 * React-query's queryClient to coordinate timeframe presets queries.
 * @internal
 */
export const timeframeQueryClient = new QueryClient({
  defaultOptions: {
    queries: {
      refetchOnWindowFocus: false,
      refetchOnMount: true,
      retry: false,
      staleTime: Infinity,
    },
  },
});
